package main

import "fmt"

type Book struct {
	Title  string
	Price  float64
	Pages  int
}

func (b *Book) SetTitle(t string) *Book  { b.Title = t; return b }
func (b *Book) SetPrice(p float64) *Book { b.Price = p; return b }
func (b *Book) SetPages(n int) *Book     { b.Pages = n; return b }
func (b *Book) Print() {
	fmt.Printf("%s — $%.2f — %d pages\n", b.Title, b.Price, b.Pages)
}

func main() {
	b := &Book{}
	b.SetTitle("Learning Go").SetPrice(39.99).SetPages(350).Print()
}

